import argparse
from json import loads as loadJsonData
from kafka import KafkaConsumer
from time import sleep


def main():

    parser = argparse.ArgumentParser(description='Process some integers.')
    parser.add_argument('--brokers', type=str, default="localhost:9092",
                        help='The addresses of the brokers (defaults to localhost)')
    
    consumer = KafkaConsumer('raw-transfers',
                             bootstrap_servers=[args.brokers],
                             group_id='consumer-group')


    for message in consumer:

        jsonMessage = loadJsonData(message.value)
        if  jsonMessage['type'] == 'balance':
            balance = jsonMessage["balance"]
            print("Account number " + str(jsonMessage["accountNumber"]) +
                  ", total of $%d.00." % (balance))
        elif  jsonMessage['type'] == 'transfer-complete':
            amount = jsonMessage["amount"]
            toAccountNumer = jsonMessage["toAccountNumber"]
            print("Transaction: $%s.00 transferred from account number " +
                  "%s, to account number %s."%(str(amount),
                                                str(jsonMessage["accountNumber"]),
                                               str(toAccountNumber)))


if __name__ == '__main__':
    args = parser.parse_args()

    main()

